    60→      const el = $el[0];
    61→      const isItalic =
    62→        el.closest("em") !== null ||
    63→        el.closest("i") !== null ||
    64→        el.tagName === "EM" ||
    65→        el.tagName === "I" ||
    66→        window.getComputedStyle(el).fontStyle === "italic";
